import os
import boto3
import pickle
import joblib
import json
from google.cloud import storage as gcs
from azure.storage.blob import BlobServiceClient
import urllib.request
import tempfile
import shutil

class ModelLoader:
    def __init__(self):
        self.model = None
        self.model_path = os.environ.get('MODEL_PATH', '')
        self.cloud_provider = os.environ.get('CLOUD_PROVIDER', 'aws')
        
    def detect_cloud_provider(self):
        if 's3://' in self.model_path:
            return 'aws'
        elif 'gs://' in self.model_path:
            return 'gcp'
        elif 'https://' in self.model_path and 'blob.core.windows.net' in self.model_path:
            return 'azure'
        elif 'http://' in self.model_path or 'https://' in self.model_path:
            return 'url'
        return self.cloud_provider
    
    def load_from_s3(self, bucket_name, key):
        s3 = boto3.client('s3')
        
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=key)
        if 'Contents' in response:
            all_objects = sorted(response['Contents'], key=lambda x: x['LastModified'], reverse=True)
            if all_objects:
                latest_key = all_objects[0]['Key']
            else:
                latest_key = key
        else:
            latest_key = key
        
        temp_file = tempfile.NamedTemporaryFile(delete=False)
        s3.download_file(bucket_name, latest_key, temp_file.name)
        
        return self.load_model_file(temp_file.name)
    
    def load_from_gcs(self, bucket_name, blob_name):
        client = gcs.Client()
        bucket = client.bucket(bucket_name)
        
        blobs = list(bucket.list_blobs(prefix=blob_name))
        if blobs:
            latest_blob = sorted(blobs, key=lambda x: x.updated, reverse=True)[0]
        else:
            latest_blob = bucket.blob(blob_name)
        
        temp_file = tempfile.NamedTemporaryFile(delete=False)
        latest_blob.download_to_filename(temp_file.name)
        
        return self.load_model_file(temp_file.name)
    
    def load_from_azure(self, connection_string, container_name, blob_name):
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container_name)
        
        blobs = list(container_client.list_blobs(name_starts_with=blob_name))
        if blobs:
            latest_blob = sorted(blobs, key=lambda x: x.last_modified, reverse=True)[0]
            blob_name = latest_blob.name
        
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        temp_file = tempfile.NamedTemporaryFile(delete=False)
        with open(temp_file.name, 'wb') as f:
            download_stream = blob_client.download_blob()
            f.write(download_stream.readall())
        
        return self.load_model_file(temp_file.name)
    
    def load_from_url(self, url):
        temp_file = tempfile.NamedTemporaryFile(delete=False)
        urllib.request.urlretrieve(url, temp_file.name)
        return self.load_model_file(temp_file.name)
    
    def load_model_file(self, file_path):
        try:
            with open(file_path, 'rb') as f:
                model = pickle.load(f)
            return model
        except:
            pass
        
        try:
            model = joblib.load(file_path)
            return model
        except:
            pass
        
        try:
            import tensorflow as tf
            model = tf.keras.models.load_model(file_path)
            return model
        except:
            pass
        
        try:
            import torch
            model = torch.load(file_path)
            return model
        except:
            pass
        
        try:
            with open(file_path, 'r') as f:
                model = json.load(f)
            return model
        except:
            pass
        
        raise Exception(f"Unable to load model from {file_path}")
    
    def load_model(self):
        provider = self.detect_cloud_provider()
        
        if provider == 'aws':
            path = self.model_path.replace('s3://', '')
            parts = path.split('/', 1)
            bucket_name = parts[0]
            key = parts[1] if len(parts) > 1 else ''
            self.model = self.load_from_s3(bucket_name, key)
            
        elif provider == 'gcp':
            path = self.model_path.replace('gs://', '')
            parts = path.split('/', 1)
            bucket_name = parts[0]
            blob_name = parts[1] if len(parts) > 1 else ''
            self.model = self.load_from_gcs(bucket_name, blob_name)
            
        elif provider == 'azure':
            connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING', '')
            path = self.model_path.split('blob.core.windows.net/')[1]
            parts = path.split('/', 1)
            container_name = parts[0]
            blob_name = parts[1] if len(parts) > 1 else ''
            self.model = self.load_from_azure(connection_string, container_name, blob_name)
            
        elif provider == 'url':
            self.model = self.load_from_url(self.model_path)
            
        else:
            self.model = self.load_model_file(self.model_path)
        
        return self.model
    
    def predict(self, input_data):
        if self.model is None:
            raise Exception("Model not loaded")
        
        if hasattr(self.model, 'predict'):
            return self.model.predict(input_data)
        elif callable(self.model):
            return self.model(input_data)
        else:
            raise Exception("Model does not support prediction")


def main():
    loader = ModelLoader()
    model = loader.load_model()
    print(f"Model loaded successfully from {loader.model_path}")
    print(f"Model type: {type(model)}")
    return loader


if __name__ == "__main__":
    loader = main()